1	export type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	export type Step = { op: "quote"; items: Item[] };
3	export type Result = { premium: number };
4	
5	const PROCESSING_FEE = 5;
6	const SWORD_BASE = 100;
7	const AMULET_BASE = 60;
8	const FIRST_INSURANCE_RATE = 0.1;
9	
10	const basePremiumFor = (item: Item): number => {
11	  if (item.type === "sword") return SWORD_BASE;
12	  if (item.type === "amulet") return AMULET_BASE;
13	  return 0;
14	};
15	
16	const quotePremium = (items: Item[]): number => {
17	  const base = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
18	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
19	  return base + firstInsuranceSurcharge + PROCESSING_FEE;
20	};
21	
22	export const runScenario = (input: {
23	  customer: { yearsWithMHPCO: number };
24	  steps: Step[];
25	}): { results: Result[] } => {
26	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
27	  return { results };
28	};
